class Solution:
    def minTimeToReach(self, moveTime):
        n = len(moveTime)
        m = len(moveTime[0])
        INF = float('inf')
        dist = [[[INF, INF] for _ in range(m)] for _ in range(n)]
        dist[0][0][0] = 0
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        changed = True
        while changed:
            changed = False
            for r in range(n):
                for c in range(m):
                    for p in range(2):
                        if dist[r][c][p] == INF:
                            continue
                        cost = 1 if p == 0 else 2
                        for dr, dc in dirs:
                            nr, nc = r + dr, c + dc
                            if 0 <= nr < n and 0 <= nc < m:
                                nt = max(dist[r][c][p], moveTime[nr][nc]) + cost
                                np_ = 1 - p
                                if nt < dist[nr][nc][np_]:
                                    dist[nr][nc][np_] = nt
                                    changed = True
        return min(dist[n - 1][m - 1][0], dist[n - 1][m - 1][1])

