import heapq
class Solution:
    def minTimeToReach(self, moveTime):
        n = len(moveTime)
        m = len(moveTime[0])
        INF = float('inf')
        dist = [[[INF, INF] for _ in range(m)] for _ in range(n)]
        dist[0][0][0] = 0
        pq = [(0, 0, 0, 0)]
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        while pq:
            t, r, c, p = heapq.heappop(pq)
            if t > dist[r][c][p]:
                continue
            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < m:
                    cost = 1 if p == 0 else 2
                    nt = max(t, moveTime[nr][nc]) + cost
                    np_ = 1 - p
                    if nt < dist[nr][nc][np_]:
                        dist[nr][nc][np_] = nt
                        heapq.heappush(pq, (nt, nr, nc, np_))
        return min(dist[n - 1][m - 1][0], dist[n - 1][m - 1][1])

