var minTimeToReach = function(moveTime) {
    const n = moveTime.length;
    const m = moveTime[0].length;
    const INF = Infinity;
    const dist = [];
    const visited = [];
    for (let r = 0; r < n; r++) {
        const rowD = [], rowV = [];
        for (let c = 0; c < m; c++) {
            rowD.push([INF, INF]);
            rowV.push([false, false]);
        }
        dist.push(rowD);
        visited.push(rowV);
    }
    dist[0][0][0] = 0;
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    const totalStates = n * m * 2;
    for (let iter = 0; iter < totalStates; iter++) {
        let br = -1, bc = -1, bp = -1, bd = Infinity;
        for (let r = 0; r < n; r++) {
            for (let c = 0; c < m; c++) {
                for (let p = 0; p < 2; p++) {
                    if (!visited[r][c][p] && dist[r][c][p] < bd) {
                        bd = dist[r][c][p];
                        br = r;
                        bc = c;
                        bp = p;
                    }
                }
            }
        }
        if (br === -1) break;
        visited[br][bc][bp] = true;
        for (const [dr, dc] of dirs) {
            const nr = br + dr, nc = bc + dc;
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const cost = bp === 0 ? 1 : 2;
                const nt = Math.max(bd, moveTime[nr][nc]) + cost;
                const np_ = 1 - bp;
                if (!visited[nr][nc][np_] && nt < dist[nr][nc][np_]) dist[nr][nc][np_] = nt;
            }
        }
    }
    return Math.min(dist[n - 1][m - 1][0], dist[n - 1][m - 1][1]);
};
